import { MetricType } from '@byted-nodex/metrics-codec';
export interface ILogger extends Record<string, any> {
    info(msg: any, ...splats: any[]): void;
    error(msg: any, ...splats: any[]): void;
    warn(msg: any, ...splats: any[]): void;
}
export interface GCOption {
    threshold: number;
    expiredDuration: number;
    /** 用于忽略某些 metric 的 gc */
    ignoreMetrics?: MetricType[];
}
export interface AnalyseCollector {
    /** 序列数量 */
    cursorCount: number;
    /** 指标数量 */
    metricCount: number;
    /** 当前活跃指标数量 */
    activeMetricCount: number;
    /** 不同指标类型的统计 */
    detail: Record<string, Pick<AnalyseCollector, 'metricCount' | 'activeMetricCount'>>;
}
